// SvgIcon — shared stroke-icon wrapper for the 今天吃什么 app.
//
// Implemented with native ArkUI Path commands (not rawfile SVGs) so icons
// honor the dynamic `color`/`strokeWidth` props — needed for selected vs
// unselected tab states and themed tints. Public API (variant, iconSize,
// color, strokeWidth) is unchanged from the scaffold contract.
//
// Path data is transcribed from the design HTML (Lucide-style 24x24 icons).
// All icons are stroke-only; the SVG gate (no .fillColor() on rawfile stroke
// icons) does not apply here because there are no rawfile images involved.

@Component
export struct SvgIcon {
  @Prop iconSize: number = 24;
  @Prop color: string = '#1A1A1A';
  @Prop strokeWidth: number = 2;
  @Prop variant: string = 'search';

  build() {
    Stack() {
      Path()
        .commands(this.commandsForVariant())
        .width(24)
        .height(24)
        .fill(Color.Transparent)
        .stroke(this.color)
        .strokeWidth(this.strokeWidth)
        .strokeLineCap(LineCapStyle.Round)
        .strokeLineJoin(LineJoinStyle.Round)
        .scale({
          x: this.iconSize / 24,
          y: this.iconSize / 24,
          centerX: '0%',
          centerY: '0%',
        })
    }
    .width(this.iconSize)
    .height(this.iconSize)
    .clip(false)
  }

  private commandsForVariant(): string {
    const v: string = this.variant;
    if (v === 'home') {
      return 'M15 21v-8a1 1 0 0 0-1-1h-4a1 1 0 0 0-1 1v8 M3 10a2 2 0 0 1 .709-1.528l7-6a2 2 0 0 1 2.582 0l7 6A2 2 0 0 1 21 10v9a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z';
